-- STEP 1: query [kommuner]
SELECT kommunenummer, kommunenavn, ST_AsGeoJSON(ST_Transform(omrade, 4326)) AS geom_geojson FROM kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenavn ILIKE '%Lillestrøm%';

-- STEP BOUNDARY --

-- STEP 2: query [kvikkleire]
SELECT ST_AsGeoJSON(ST_Transform(omrade, 4326)) AS geom_geojson FROM kvikkleire_175185730654415d8841436d0d6999f2.utlosningomr WHERE ST_Intersects(omrade, ST_Transform(ST_GeomFromGeoJSON('{"type":"MultiPolygon","coordinates":[[[[11.05,59.95],[11.05,60.05],[11.15,60.05],[11.15,59.95],[11.05,59.95]]]]}'), 25833));

-- STEP BOUNDARY --

-- STEP 3: query [matrikkeleneiendomskartteig]
SELECT ST_AsGeoJSON(ST_Transform(t.omrade, 4326)) AS geom_geojson FROM matrikkeleneiendomskartteig_36313fab8faa42d99cb779d86d1ca26d.teig t WHERE t.kommunenummer = '3205' AND EXISTS (SELECT 1 FROM kvikkleire_175185730654415d8841436d0d6999f2.utlosningomr k WHERE ST_Intersects(t.omrade, k.omrade));
